#[cfg(test)]
mod tests {
    use super::*;
    use mockall::predicate::*;
    use assert_matches::assert_matches;

    fn create_test_user() -> User {
        User { id: 1, email: "test@example.com".into(), ..Default::default() }
    }

    #[tokio::test(flavor = "multi_thread", worker_threads = 2)]
    async fn test_get_by_id_returns_user() {
        let mut mock_db = MockDatabase::new();
        mock_db.expect_fetch_user_by_id()
            .with(eq(1))
            .times(1)
            .returning(|_| Ok(Some(create_test_user())));

        let service = UserService::new(Arc::new(mock_db));
        let result = service.get_by_id(1).await;

        assert!(result.is_ok());
        assert_eq!(result.unwrap().email, "test@example.com");
    }

    #[tokio::test]
    async fn test_get_by_id_not_found() {
        let mut mock_db = MockDatabase::new();
        mock_db.expect_fetch_user_by_id()
            .returning(|_| Ok(None));

        let service = UserService::new(Arc::new(mock_db));
        let result = service.get_by_id(999).await;

        assert_matches!(result, Err(AppError::NotFound(_)));
    }
}

// tests/api_tests.rs
use axum::{body::Body, http::{Request, StatusCode}};
use tower::ServiceExt;
use serde_json::json;

#[tokio::test]
async fn test_create_user_returns_201() {
    let app = create_test_app().await;

    let response = app
        .oneshot(
            Request::builder()
                .method("POST")
                .uri("/api/v1/users")
                .header("Content-Type", "application/json")
                .body(Body::from(
                    json!({"name": "Alice", "email": "alice@example.com", "password": "pass123"})
                    .to_string(),
                ))
                .unwrap(),
        )
        .await
        .unwrap();

    assert_eq!(response.status(), StatusCode::CREATED);
    let body = axum::body::to_bytes(response.into_body(), usize::MAX).await.unwrap();
    let user: serde_json::Value = serde_json::from_slice(&body).unwrap();
    assert_eq!(user["email"], "alice@example.com");
}

use proptest::prelude::*;

proptest! {
    // Round-trip invariant: parse(serialize(x)) == x
    #[test]
    fn round_trip_serialization(input in any::<ValidAst>()) {
        let serialized = serialize(&input);
        let parsed = parse(&serialized).expect("should parse serialized output");
        prop_assert_eq!(input, parsed);
    }

    // No-panic invariant: parse never panics on arbitrary bytes
    #[test]
    fn parse_never_panics(data in prop::collection::vec(any::<u8>(), 0..=1024)) {
        // We don't care about the result, only that it doesn't panic
        let _ = parse_bytes(&data);
    }
}
